import{_ as n,Z as t,P as l,g as r,k as p,m as e}from"./chunks/framework.Dp5g00Bf.js";const m=JSON.parse('{"title":"BBR网络加速","description":"","frontmatter":{},"headers":[],"relativePath":"views/1-开发🌏/3-运维/开启BBR网络加速/index.md","filePath":"views/1-开发🌏/3-运维/开启BBR网络加速/index.md","lastUpdated":1778639396000}'),d={name:"views/1-开发🌏/3-运维/开启BBR网络加速/index.md"};function h(o,s,c,b,k,g){const a=t("NolebaseGitContributors"),i=t("NolebaseGitChangelog");return l(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778639396000"},[s[0]||(s[0]=p(`<h1 id="bbr网络加速" tabindex="-1">BBR网络加速 <a class="header-anchor" href="#bbr网络加速" aria-label="Permalink to &quot;BBR网络加速&quot;">​</a></h1><p>传统的拥塞控制算法（如 CUBIC）在遇到网络丢包时会剧烈降低发送速度。而 <strong>BBR</strong> 是谷歌开发的算法，它通过分析带宽和往返时间（RTT）来寻找最佳发送速率。它对于海外服务与跨境网络访问的提升实测还是很明显的，如果你有海外的云服务器请务必开启，可以显著增加国内的访问速度。</p><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">传统算法 (CUBIC)</th><th style="text-align:left;">Google BBR</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>丢包处理</strong></td><td style="text-align:left;">将丢包视为拥塞，大幅减速</td><td style="text-align:left;">区分随机丢包与拥塞，保持高速</td></tr><tr><td style="text-align:left;"><strong>吞吐量</strong></td><td style="text-align:left;">在高延迟/高丢包环境下表现较差</td><td style="text-align:left;">显著提升长途链路的传输速度</td></tr><tr><td style="text-align:left;"><strong>延迟</strong></td><td style="text-align:left;">容易填满缓冲区导致延迟增加 (Bufferbloat)</td><td style="text-align:left;">倾向于降低排队延迟</td></tr></tbody></table><h2 id="ubuntu-开启-bbr" tabindex="-1">ubuntu 开启 BBR <a class="header-anchor" href="#ubuntu-开启-bbr" aria-label="Permalink to &quot;ubuntu 开启 BBR&quot;">​</a></h2><p>在 Ubuntu 上开启 BBR（Bottleneck Bandwidth and Round-trip propagation time）加速非常简单，因为从 Ubuntu 18.10 及更高版本开始，Linux 内核（4.19+）已经内置了 BBR 模块。</p><p>以下是开启 BBR 的标准步骤：</p><h3 id="_1-检查当前内核版本" tabindex="-1">1. 检查当前内核版本 <a class="header-anchor" href="#_1-检查当前内核版本" aria-label="Permalink to &quot;1. 检查当前内核版本&quot;">​</a></h3><p>首先，确保你的内核版本高于 <strong>4.19</strong>。在终端输入：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果输出的版本号大于 4.19，即可直接开启。</p><hr><h3 id="_2-修改系统变量" tabindex="-1">2. 修改系统变量 <a class="header-anchor" href="#_2-修改系统变量" aria-label="Permalink to &quot;2. 修改系统变量&quot;">​</a></h3><p>我们需要将 BBR 配置写入 <code>sysctl.conf</code> 配置文件中。</p><ol><li><strong>执行以下命令，将配置添加到文件末尾：</strong></li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;net.core.default_qdisc=fq&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/sysctl.conf</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;net.ipv4.tcp_congestion_control=bbr&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/sysctl.conf</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol start="2"><li><strong>刷新配置使其立即生效：</strong></li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="_3-验证-bbr-是否开启成功" tabindex="-1">3. 验证 BBR 是否开启成功 <a class="header-anchor" href="#_3-验证-bbr-是否开启成功" aria-label="Permalink to &quot;3. 验证 BBR 是否开启成功&quot;">​</a></h3><p>通过以下两个命令来确认 BBR 是否正在运行：</p><ul><li><strong>检查拥塞控制算法：</strong></li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.ipv4.tcp_congestion_control</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p><strong>预期输出：</strong> <code>net.ipv4.tcp_congestion_control = bbr</code></p></blockquote><ul><li><strong>检查内核模块是否加载：</strong></li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsmod</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bbr</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p><strong>预期输出：</strong> 看到 <code>tcp_bbr</code> 相关的字样，说明模块已成功启动。</p></blockquote><h2 id="windows-开启-bbr" tabindex="-1">Windows 开启 BBR <a class="header-anchor" href="#windows-开启-bbr" aria-label="Permalink to &quot;Windows 开启 BBR&quot;">​</a></h2><p>实际上，从 Windows 10 (1709) 开始，微软就在 TCP 协议栈中引入了对 BBR 的支持。在 Windows 11 中，默认支持的是 BBR v2 版本（虽然在命令行中统一称为 bbr）。</p><h3 id="_1-查看当前配置" tabindex="-1">1. 查看当前配置 <a class="header-anchor" href="#_1-查看当前配置" aria-label="Permalink to &quot;1. 查看当前配置&quot;">​</a></h3><p>打开 PowerShell，输入以下命令查看当前配置：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">netsh int tcp show supplemental</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-开启-bbr" tabindex="-1">2. 开启 BBR <a class="header-anchor" href="#_2-开启-bbr" aria-label="Permalink to &quot;2. 开启 BBR&quot;">​</a></h3><p>将 Internet 和 Datacenter 模板设置为 BBR2：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">netsh int tcp set supplemental template</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">internet congestionprovider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bbr2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">netsh int tcp set supplemental template</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">datacenter congestionprovider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bbr2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><blockquote><p><strong>注意</strong>：Windows 11 默认的 Internet 模板通常已经是 <code>bbr2</code>，执行上述命令可以确保生效。</p></blockquote><h3 id="_3-进阶设置-可选" tabindex="-1">3. 进阶设置（可选） <a class="header-anchor" href="#_3-进阶设置-可选" aria-label="Permalink to &quot;3. 进阶设置（可选）&quot;">​</a></h3><p>如果你希望<strong>彻底</strong>应用 BBR，建议将 Custom 模板也进行设置，以确保万无一失：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">netsh int tcp set supplemental template</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">internetcustom congestionprovider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bbr2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">netsh int tcp set supplemental template</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">datacentercustom congestionprovider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bbr2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_4-验证是否开启成功" tabindex="-1">4. 验证是否开启成功 <a class="header-anchor" href="#_4-验证是否开启成功" aria-label="Permalink to &quot;4. 验证是否开启成功&quot;">​</a></h3><p>再次执行查看命令确认：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">netsh int tcp show supplemental</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>预期输出：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">模板</th><th style="text-align:left;">拥塞控制算法</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Internet</code></td><td style="text-align:left;"><code>BBR2</code></td></tr><tr><td style="text-align:left;"><code>Datacenter</code></td><td style="text-align:left;"><code>BBR2</code></td></tr><tr><td style="text-align:left;"><code>InternetCustom</code></td><td style="text-align:left;"><code>BBR2</code></td></tr><tr><td style="text-align:left;"><code>DatacenterCustom</code></td><td style="text-align:left;"><code>BBR2</code></td></tr></tbody></table><h3 id="_5-如何测试效果" tabindex="-1">5. 如何测试效果？ <a class="header-anchor" href="#_5-如何测试效果" aria-label="Permalink to &quot;5. 如何测试效果？&quot;">​</a></h3><p>开启 BBR 后，你不会在刷网页时感觉到&quot;瞬间起飞&quot;，但在以下场景中会有明显改善：</p><ol><li><strong>跨境访问</strong>：由于往返时间（RTT）较长，BBR 能维持更稳定的高速连接。</li><li><strong>大文件传输</strong>：在有轻微丢包的网络下，下载速度波动会变小。</li><li><strong>高负载网络</strong>：当家里多人同时抢带宽时，BBR 的抗干扰能力更强。</li></ol><p><strong>建议重启浏览器，或者尝试下载一个大文件，观察速度曲线是否比以前更平滑。</strong></p><hr>`,48)),e(a),e(i)])}const y=n(d,[["render",h]]);export{m as __pageData,y as default};
